/* ============================== GLOBAL HELPERS ============================== */
function fmtDate(val) {
  if (val === null || val === undefined || val === '') return '';
  let d;
  if (val instanceof Date) {
    d = val;
  } else if (typeof val === 'number') {
    // Google Sheets serial date (days since Dec 30 1899)
    d = new Date(Math.round((val - 25569) * 86400 * 1000));
  } else if (typeof val === 'string') {
    const s = val.trim();
    if (/^\d+(\.\d+)?$/.test(s)) {
      d = new Date(Math.round((parseFloat(s) - 25569) * 86400 * 1000));
    } else {
      d = new Date(s);
    }
  } else {
    return String(val);
  }
  if (isNaN(d.getTime())) return String(val);
  const months = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
  return `${String(d.getDate()).padStart(2,'0')} ${months[d.getMonth()]} ${d.getFullYear()}`;
}

function fmtDateInput(val) {
  // returns YYYY-MM-DD for <input type=date>
  if (!val) return '';
  let d;
  if (val instanceof Date) d = val;
  else if (typeof val === 'number') d = new Date(Math.round((val - 25569) * 86400 * 1000));
  else if (typeof val === 'string') {
    const s = val.trim();
    if (/^\d{4}-\d{2}-\d{2}/.test(s)) return s.slice(0,10);
    if (/^\d+(\.\d+)?$/.test(s)) d = new Date(Math.round((parseFloat(s) - 25569) * 86400 * 1000));
    else d = new Date(s);
  } else return '';
  if (isNaN(d.getTime())) return '';
  return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`;
}

function mergeById(sheetArr, localArr) {
  const map = new Map();
  (sheetArr || []).forEach(r => map.set(r._id, r));
  (localArr || []).forEach(r => map.set(r._id, r));
  return Array.from(map.values());
}

function uid() {
  return Math.random().toString(36).slice(2) + Date.now().toString(36);
}

