let _jsonpCounter = 0;
function jsonpRequest(url, params, timeoutMs = 20000) {
  return new Promise((resolve, reject) => {
    const cbName = '__acc_cb_' + (++_jsonpCounter) + '_' + Date.now();
    const script = document.createElement('script');
    let timeout;
    const cleanup = () => {
      delete window[cbName];
      if (script.parentNode) script.parentNode.removeChild(script);
      clearTimeout(timeout);
    };
    window[cbName] = (data) => { cleanup(); resolve(data); };
    timeout = setTimeout(() => { cleanup(); reject(new Error('Request timed out')); }, timeoutMs);
    const qs = new URLSearchParams({ ...params, callback: cbName }).toString();
    script.src = url + (url.includes('?') ? '&' : '?') + qs;
    script.onerror = () => { cleanup(); reject(new Error('Network error (script load failed)')); };
    document.body.appendChild(script);
  });
}

async function sheetRead(webhookUrl) {
  if (!webhookUrl) throw new Error('Webhook URL not configured');
  try {
    const res = await fetch(webhookUrl + '?action=readAll', { method: 'GET' });
    if (res.ok) {
      const data = await res.json();
      if (data && !data.error) return data;
    }
  } catch (e) { /* fall through to JSONP */ }
  const data = await jsonpRequest(webhookUrl, { action: 'readAll' });
  if (data && data.error) throw new Error(data.error);
  return data;
}

async function sheetPost(webhookUrl, payload) {
  if (!webhookUrl) throw new Error('Webhook URL not configured');
  try {
    const res = await fetch(webhookUrl, {
      method: 'POST',
      headers: { 'Content-Type': 'text/plain;charset=utf-8' },
      body: JSON.stringify(payload),
    });
    if (res.ok) {
      try { return await res.json(); } catch (e) { return { status: 'ok' }; }
    }
  } catch (e) { /* fall through */ }
  try {
    await fetch(webhookUrl, { method: 'POST', mode: 'no-cors', headers: { 'Content-Type': 'text/plain;charset=utf-8' }, body: JSON.stringify(payload) });
  } catch (e) {}
  return { status: 'ok', note: 'no-cors fallback' };
}

async function sheetTest(webhookUrl) {
  if (!webhookUrl) throw new Error('Webhook URL not configured');
  try {
    const res = await fetch(webhookUrl + '?action=test', { method: 'GET' });
    if (res.ok) return await res.json();
  } catch (e) {}
  return await jsonpRequest(webhookUrl, { action: 'test' });
}

