/* ============================== UI PRIMITIVES ============================== */
function Pill({ text, color }) {
  return <span style={{
    display: 'inline-block', padding: '3px 10px', borderRadius: 999, fontSize: 12, fontWeight: 600,
    background: color + '22', color: color, whiteSpace: 'nowrap',
  }}>{text}</span>;
}

function Button({ children, onClick, variant = 'default', style, type = 'button', disabled, title }) {
  const base = {
    padding: '8px 14px', borderRadius: 8, fontSize: 13, fontWeight: 600, cursor: disabled ? 'not-allowed' : 'pointer',
    display: 'inline-flex', alignItems: 'center', gap: 6, border: '1px solid transparent', transition: 'all .15s',
    opacity: disabled ? 0.6 : 1,
  };
  const variants = {
    default: { background: S.accent, color: S.accentText, border: `1px solid ${S.accent}` },
    secondary: { background: S.cardBg, color: S.textPrimary, border: `1px solid ${S.border2}` },
    danger: { background: S.danger, color: '#fff', border: `1px solid ${S.danger}` },
    ghost: { background: 'transparent', color: S.textSecondary, border: `1px solid transparent` },
  };
  return <button type={type} title={title} disabled={disabled} onClick={onClick} style={{ ...base, ...variants[variant], ...style }}>{children}</button>;
}

function Field({ label, children, required }) {
  return (
    <div style={{ marginBottom: 14 }}>
      <label style={{ display: 'block', fontSize: 12, fontWeight: 600, color: S.textSubtle, marginBottom: 5 }}>
        {label}{required && <span style={{ color: S.danger }}> *</span>}
      </label>
      {children}
    </div>
  );
}

const inputStyle = () => ({
  width: '100%', padding: '9px 12px', borderRadius: 8, border: `1px solid ${S.border2}`,
  background: S.inputBg, color: S.textPrimary, fontSize: 13, outline: 'none', boxSizing: 'border-box',
  fontFamily: 'inherit',
});

function TextInput(props) {
  return <input {...props} style={{ ...inputStyle(), ...(props.style || {}) }} />;
}
function TextArea(props) {
  return <textarea {...props} style={{ ...inputStyle(), resize: 'vertical', minHeight: 80, ...(props.style || {}) }} />;
}
function Select({ value, onChange, options, placeholder, disabled }) {
  return (
    <select value={value || ''} onChange={onChange} disabled={disabled} style={{ ...inputStyle(), cursor: disabled ? 'not-allowed' : 'pointer', opacity: disabled ? 0.6 : 1 }}>
      <option value="">{placeholder || 'Select...'}</option>
      {options.map(o => <option key={o} value={o}>{o}</option>)}
    </select>
  );
}

function Modal({ title, onClose, children, footer, width = 640 }) {
  return (
    <div style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.55)', zIndex: 1000, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 16 }} onMouseDown={(e) => { if (e.target === e.currentTarget) onClose(); }}>
      <div style={{ background: S.cardBg, borderRadius: 14, width: '100%', maxWidth: width, maxHeight: '92vh', display: 'flex', flexDirection: 'column', boxShadow: '0 20px 60px rgba(0,0,0,0.3)', border: `1px solid ${S.border}` }}>
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '16px 20px', borderBottom: `1px solid ${S.border}` }}>
          <div style={{ fontSize: 16, fontWeight: 700, color: S.textHighlight }}>{title}</div>
          <button onClick={onClose} style={{ background: 'transparent', border: 'none', cursor: 'pointer', color: S.textMuted, padding: 4 }}><Icon name="x" /></button>
        </div>
        <div style={{ padding: 20, overflowY: 'auto', flex: 1 }}>{children}</div>
        {footer && <div style={{ padding: '14px 20px', borderTop: `1px solid ${S.border}`, display: 'flex', justifyContent: 'flex-end', gap: 10 }}>{footer}</div>}
      </div>
    </div>
  );
}

