/* ============================== CLASSIFICATION COLORS ============================== */
const CLASS_COLORS = {
  'P.M.': S.info ? null : null, // placeholder, resolved at render time via function below
};
function classColor(cls) {
  switch (cls) {
    case 'P.M.': return S.info;
    case 'Breakdown': return S.danger;
    case 'Overhaul': return S.warning;
    case 'Kiln Overhaul': return S.pillWarning;
    case 'RestStoppage': return S.textMuted;
    default: return S.textMuted;
  }
}

/* ============================== CODE LIST HELPERS ============================== */
function buildCodeMaps(codeList) {
  const lines = new Set();
  const equipByLine = {}; // line -> Set
  const codeByLineEquip = {}; // "line||equip" -> Set
  (codeList || []).forEach(c => {
    if (!c.line || !c.equipment) return;
    lines.add(c.line);
    if (!equipByLine[c.line]) equipByLine[c.line] = new Set();
    equipByLine[c.line].add(c.equipment);
    const key = c.line + '||' + c.equipment;
    if (!codeByLineEquip[key]) codeByLineEquip[key] = new Set();
    if (c.equipmentCode) codeByLineEquip[key].add(c.equipmentCode);
  });
  return {
    lines: Array.from(lines).sort(),
    equipByLine,
    codeByLineEquip,
    getEquipment: (line) => line && equipByLine[line] ? Array.from(equipByLine[line]).sort() : [],
    getCodes: (line, equip) => {
      const key = line + '||' + equip;
      return codeByLineEquip[key] ? Array.from(codeByLineEquip[key]).sort() : [];
    }
  };
}

