/* ============================== DONUT CHART ============================== */
function DonutChart({ data, size = 180, thickness = 30 }) {
  const total = data.reduce((s, d) => s + d.value, 0) || 1;
  const radius = (size - thickness) / 2;
  const circumference = 2 * Math.PI * radius;
  let offset = 0;
  return (
    <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`}>
      <g transform={`rotate(-90 ${size / 2} ${size / 2})`}>
        <circle cx={size / 2} cy={size / 2} r={radius} fill="none" stroke={S.border} strokeWidth={thickness} />
        {data.filter(d => d.value > 0).map((d, i) => {
          const frac = d.value / total;
          const dash = frac * circumference;
          const el = <circle key={i} cx={size / 2} cy={size / 2} r={radius} fill="none" stroke={d.color} strokeWidth={thickness}
            strokeDasharray={`${dash} ${circumference - dash}`} strokeDashoffset={-offset} strokeLinecap="butt" />;
          offset += dash;
          return el;
        })}
      </g>
      <text x="50%" y="48%" textAnchor="middle" dominantBaseline="central" style={{ fontSize: 26, fontWeight: 800, fill: S.textHighlight }}>{total}</text>
      <text x="50%" y="66%" textAnchor="middle" dominantBaseline="central" style={{ fontSize: 11, fontWeight: 600, fill: S.textMuted }}>TOTAL</text>
    </svg>
  );
}

